        return new Source("{% extends \x27base.html.twig\x27 %}

{% block title %}Adresse index{% endblock %}

{% block body %}
    <h1>Adresse index</h1>

    <table class=\"table\">
        <thead>
            <tr>
                <th>Id</th>
                <th>NumRue</th>
                <th>NomRue</th>
                <th>Cp</th>
                <th>NomVille</th>
                <th>actions</th>
            </tr>
        </thead>
        <tbody>
        {% for adresse in adresses %}
            <tr>
                <td>{{ adresse.id }}</td>
                <td>{{ adresse.numRue }}</td>
                <td>{{ adresse.nomRue }}</td>
                <td>{{ adresse.cp }}</td>
                <td>{{ adresse.nomVille }}</td>
                <td>
                    <a href=\"{{ path(\x27adresse_show\x27, {\x27id\x27: adresse.id}) }}\">
                        <button type=\"button\" class=\"btn btn-outline-dark\">Voir</button>
                    </a>
                    <a href=\"{{ path(\x27adresse_edit\x27, {\x27id\x27: adresse.id}) }}\">
                        <button type=\"button\" class=\"btn btn-outline-dark\">Edition</button>
                    </a>
                </td>
            </tr>
        {% else %}
            <tr>
                <td colspan=\"6\">no records found</td>
            </tr>
        {% endfor %}
        </tbody>
    </table>

    <a href=\"{{ path(\x27adresse_new\x27) }}\">
        <button type=\"button\" class=\"btn btn-outline-dark\">Créer</button>
    </a>
{% endblock %}
